final:
module RefModule(
    input u,
    input v,
    input w,
    input s0,
    input s1,
    output m
    );wire obf_tra;

    // Implementing (~s0 & u) | (s0 & v)
    assign obf_tra = (~s0 & u) | (s0 & v);

    // Implementing (~s1 & obf_tra) | (s1 & w)
    assign m = (~s1 & obf_tra) | (s1 & w);

endmodule
